"use client";

import {
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
} from "react";
import type {
  DetailPanelContextValue,
  DetailPanelHandle,
  DetailPanelProps,
} from "./types";
import { DetailPanelContext } from "./parts/detail-panel-context";
import { DetailPanelHeader } from "./parts/detail-panel-header";
import { DetailPanelBody } from "./parts/detail-panel-body";
import { DetailPanelActions } from "./parts/detail-panel-actions";
import { DetailPanelEmptyState } from "./parts/detail-panel-empty-state";
import { DetailPanelSkeleton } from "./parts/detail-panel-skeleton";
import { DetailPanelError } from "./parts/detail-panel-error";
import { SelectionAnnouncer } from "./parts/selection-announcer";
import { useDetailPanelMode } from "./hooks/use-detail-panel-mode";
import { useFocusRestore } from "./hooks/use-focus-restore";
import { keyForSelection } from "./lib/selection-key";
import { cn } from "@/lib/utils";

const FOCUSABLE =
  'input, textarea, select, button, [tabindex]:not([tabindex="-1"]), [contenteditable="true"]';

function DetailPanelImpl({
  selection,
  mode: controlledMode,
  onModeChange,
  canEdit = true,
  loading = false,
  error = null,
  emptyState,
  children,
  ariaLabel,
  className,
  ref,
}: DetailPanelProps) {
  const rootRef = useRef<HTMLDivElement>(null);
  const bodyRef = useRef<HTMLDivElement>(null);

  const selectionKey = useMemo(() => keyForSelection(selection), [selection]);

  const { mode, setMode } = useDetailPanelMode({
    controlledMode,
    onModeChange,
    selectionKey,
  });

  const { captureTrigger } = useFocusRestore({ mode, rootRef, bodyRef });

  const wrappedSetMode = useCallback(
    (next: typeof mode) => {
      captureTrigger();
      setMode(next);
    },
    [captureTrigger, setMode],
  );

  const hasError = !!error;
  const hasSelection = selection !== null;

  const lastSelectionKeyRef = useRef(selectionKey);
  useEffect(() => {
    if (lastSelectionKeyRef.current === selectionKey) return;
    lastSelectionKeyRef.current = selectionKey;
    rootRef.current?.focus({ preventScroll: true });
  }, [selectionKey]);

  const focusBody = useCallback(() => {
    const body = bodyRef.current;
    if (!body) return;
    const focusable = body.querySelector<HTMLElement>(FOCUSABLE);
    (focusable ?? body).focus();
  }, []);

  const resetMode = useCallback(() => {
    setMode("read");
  }, [setMode]);

  useImperativeHandle(
    ref,
    (): DetailPanelHandle => ({
      focusBody,
      resetMode,
    }),
    [focusBody, resetMode],
  );

  const ctx: DetailPanelContextValue = useMemo(
    () => ({
      selection,
      mode,
      setMode: wrappedSetMode,
      canEdit,
      loading,
      hasError,
      selectionKey,
      bodyRef,
    }),
    [
      selection,
      mode,
      wrappedSetMode,
      canEdit,
      loading,
      hasError,
      selectionKey,
    ],
  );

  let body: React.ReactNode;
  if (hasError && error) {
    body = <DetailPanelError error={error} />;
  } else if (loading) {
    body = <DetailPanelSkeleton />;
  } else if (!hasSelection) {
    body = emptyState ?? <DetailPanelEmptyState />;
  } else {
    body = (
      <div key={selectionKey} className="contents">
        {children}
      </div>
    );
  }

  return (
    <DetailPanelContext.Provider value={ctx}>
      <div
        ref={rootRef}
        role="region"
        aria-label={ariaLabel}
        aria-busy={loading || undefined}
        tabIndex={-1}
        className={cn(
          "relative flex h-full flex-col overflow-hidden rounded-md border border-border bg-card text-card-foreground outline-none focus-visible:ring-2 focus-visible:ring-ring",
          className,
        )}
      >
        <SelectionAnnouncer selectionKey={selectionKey} />
        {body}
      </div>
    </DetailPanelContext.Provider>
  );
}

type DetailPanelComponent = ((props: DetailPanelProps) => React.JSX.Element) & {
  Header: typeof DetailPanelHeader;
  Body: typeof DetailPanelBody;
  Actions: typeof DetailPanelActions;
};

export const DetailPanel = DetailPanelImpl as unknown as DetailPanelComponent;
DetailPanel.Header = DetailPanelHeader;
DetailPanel.Body = DetailPanelBody;
DetailPanel.Actions = DetailPanelActions;

export { DetailPanelEmptyState };

export { DetailPanel, DetailPanelEmptyState } from "./detail-panel";
export type {
  DetailPanelActionsContext,
  DetailPanelActionsProps,
  DetailPanelActionsRenderFn,
  DetailPanelBodyProps,
  DetailPanelError,
  DetailPanelHandle,
  DetailPanelHeaderProps,
  DetailPanelMode,
  DetailPanelProps,
  DetailPanelSelection,
} from "./types";
export { meta } from "./meta";

import type { ReactNode, Ref, RefObject } from "react";

export type DetailPanelMode = "read" | "edit";

export interface DetailPanelSelection {
  type: string;
  id: string;
}

export interface DetailPanelError {
  message: string;
  retry?: () => void;
}

export interface DetailPanelActionsContext {
  mode: DetailPanelMode;
  setMode: (next: DetailPanelMode) => void;
  canEdit: boolean;
}

export type DetailPanelActionsRenderFn = (
  ctx: DetailPanelActionsContext,
) => ReactNode;

export interface DetailPanelProps {
  selection: DetailPanelSelection | null;

  mode?: DetailPanelMode;
  onModeChange?: (mode: DetailPanelMode) => void;

  canEdit?: boolean;

  loading?: boolean;
  error?: DetailPanelError | null;

  emptyState?: ReactNode;

  children: ReactNode;

  ariaLabel?: string;
  className?: string;

  ref?: Ref<DetailPanelHandle>;
}

export interface DetailPanelHeaderProps {
  children: ReactNode;
  sticky?: boolean;
  className?: string;
}

export interface DetailPanelBodyProps {
  children: ReactNode;
  className?: string;
}

export interface DetailPanelActionsProps {
  children: ReactNode | DetailPanelActionsRenderFn;
  position?: "footer" | "header";
  className?: string;
}

export interface DetailPanelHandle {
  focusBody(): void;
  resetMode(): void;
}

export interface DetailPanelContextValue {
  selection: DetailPanelSelection | null;
  mode: DetailPanelMode;
  setMode: (next: DetailPanelMode) => void;
  canEdit: boolean;
  loading: boolean;
  hasError: boolean;
  selectionKey: string;
  bodyRef: RefObject<HTMLDivElement | null>;
}

import { useCallback, useEffect, useRef, useState } from "react";
import type { DetailPanelMode } from "../types";

interface UseModeArgs {
  controlledMode: DetailPanelMode | undefined;
  onModeChange: ((mode: DetailPanelMode) => void) | undefined;
  selectionKey: string;
}

interface UseModeResult {
  mode: DetailPanelMode;
  setMode: (next: DetailPanelMode) => void;
  isLocked: boolean;
}

interface ModeSnapshot {
  mode: DetailPanelMode;
  key: string;
}

export function useDetailPanelMode({
  controlledMode,
  onModeChange,
  selectionKey,
}: UseModeArgs): UseModeResult {
  const isControlled = controlledMode !== undefined;
  const isLocked = isControlled && !onModeChange;

  // Uncontrolled-only state. Derived `mode` returns "read" when the snapshot's
  // key doesn't match the current selectionKey — this is how the auto-reset
  // contract is honored without a setState-in-effect.
  const [snapshot, setSnapshot] = useState<ModeSnapshot>({
    mode: "read",
    key: selectionKey,
  });

  const warnedLockedMountRef = useRef(false);
  useEffect(() => {
    if (!isLocked) return;
    if (warnedLockedMountRef.current) return;
    warnedLockedMountRef.current = true;
    if (process.env.NODE_ENV !== "production") {
      console.warn(
        "[detail-panel] `mode` is supplied without `onModeChange`. " +
          "The panel cannot honor the auto-reset contract for selection changes. " +
          "Pass `onModeChange` to enable the controlled configuration, or omit `mode` to use uncontrolled.",
      );
    }
  }, [isLocked]);

  // Controlled-mode auto-reset: notify host of the mode change to "read" on
  // selection change (host owns state — this is a callback, not a setState).
  const lastReportedKeyRef = useRef(selectionKey);
  useEffect(() => {
    if (!isControlled || isLocked) return;
    if (lastReportedKeyRef.current === selectionKey) return;
    lastReportedKeyRef.current = selectionKey;
    if (controlledMode !== "read" && onModeChange) {
      onModeChange("read");
    }
  }, [selectionKey, isControlled, isLocked, controlledMode, onModeChange]);

  const lastWarnedLockedKeyRef = useRef(selectionKey);
  useEffect(() => {
    if (!isLocked) return;
    if (lastWarnedLockedKeyRef.current === selectionKey) return;
    lastWarnedLockedKeyRef.current = selectionKey;
    if (process.env.NODE_ENV !== "production") {
      console.warn(
        "[detail-panel] selection changed but the panel is in locked mode " +
          "(no `onModeChange`); auto-reset to `\"read\"` cannot fire.",
      );
    }
  }, [selectionKey, isLocked]);

  const setMode = useCallback(
    (next: DetailPanelMode) => {
      if (isLocked) {
        if (process.env.NODE_ENV !== "production") {
          console.warn(
            "[detail-panel] setMode called in locked mode; pass `onModeChange` to enable mode toggling.",
          );
        }
        return;
      }
      if (isControlled) {
        onModeChange?.(next);
        return;
      }
      // Snapshot the current selectionKey alongside the mode so the
      // derived-mode logic resets cleanly on subsequent selection changes.
      setSnapshot({ mode: next, key: selectionKey });
    },
    [isLocked, isControlled, onModeChange, selectionKey],
  );

  let mode: DetailPanelMode;
  if (isControlled) {
    mode = controlledMode as DetailPanelMode;
  } else if (snapshot.key === selectionKey) {
    mode = snapshot.mode;
  } else {
    mode = "read";
  }

  return { mode, setMode, isLocked };
}

"use client";

import { useEffect, useRef } from "react";
import type { DetailPanelMode } from "../types";

interface UseFocusRestoreArgs {
  mode: DetailPanelMode;
  rootRef: React.RefObject<HTMLDivElement | null>;
  bodyRef: React.RefObject<HTMLDivElement | null>;
}

const FOCUSABLE =
  'input, textarea, select, button, [tabindex]:not([tabindex="-1"]), [contenteditable="true"]';

export function useFocusRestore({
  mode,
  rootRef,
  bodyRef,
}: UseFocusRestoreArgs): {
  captureTrigger: () => void;
} {
  const triggerIdRef = useRef<string | null>(null);
  const lastModeRef = useRef<DetailPanelMode>(mode);

  const captureTrigger = () => {
    if (typeof document === "undefined") return;
    const active = document.activeElement;
    if (active instanceof HTMLElement && active.id) {
      triggerIdRef.current = active.id;
    } else {
      triggerIdRef.current = null;
    }
  };

  useEffect(() => {
    const previous = lastModeRef.current;
    lastModeRef.current = mode;
    if (previous === mode) return;

    if (mode === "edit") {
      const body = bodyRef.current;
      if (!body) return;
      const focusable = body.querySelector<HTMLElement>(FOCUSABLE);
      (focusable ?? body).focus();
      return;
    }
    if (mode === "read" && previous === "edit") {
      const id = triggerIdRef.current;
      if (id && typeof document !== "undefined") {
        const target = document.getElementById(id);
        if (target instanceof HTMLElement) {
          target.focus();
          triggerIdRef.current = null;
          return;
        }
      }
      const root = rootRef.current;
      root?.focus();
    }
  }, [mode, bodyRef, rootRef]);

  return { captureTrigger };
}

import type { DetailPanelSelection } from "../types";

export const EMPTY_SELECTION_KEY = "__empty__";

export function keyForSelection(
  selection: DetailPanelSelection | null,
): string {
  if (!selection) return EMPTY_SELECTION_KEY;
  return `${selection.type}:${selection.id}`;
}

"use client";

import type {
  DetailPanelActionsProps,
  DetailPanelActionsRenderFn,
} from "../types";
import { useDetailPanel } from "./detail-panel-context";
import { cn } from "@/lib/utils";

function isRenderFn(
  children: DetailPanelActionsProps["children"],
): children is DetailPanelActionsRenderFn {
  return typeof children === "function";
}

export function DetailPanelActions({
  children,
  position = "footer",
  className,
}: DetailPanelActionsProps) {
  const { mode, setMode, canEdit } = useDetailPanel();
  const content = isRenderFn(children)
    ? children({ mode, setMode, canEdit })
    : children;

  const isFooter = position === "footer";

  return (
    <div
      role="toolbar"
      className={cn(
        "z-10 flex items-center justify-end gap-2 bg-background",
        isFooter
          ? "sticky bottom-0 border-t border-border px-4 py-3"
          : "ml-auto",
        className,
      )}
    >
      {content}
    </div>
  );
}

"use client";

import type { DetailPanelBodyProps } from "../types";
import { useDetailPanel } from "./detail-panel-context";
import { cn } from "@/lib/utils";

export function DetailPanelBody({
  children,
  className,
}: DetailPanelBodyProps) {
  const { bodyRef } = useDetailPanel();
  return (
    <div
      ref={bodyRef}
      tabIndex={-1}
      className={cn(
        "flex-1 overflow-y-auto px-4 py-4 outline-none",
        className,
      )}
    >
      {children}
    </div>
  );
}

"use client";

import { createContext, useContext } from "react";
import type { DetailPanelContextValue } from "../types";

export const DetailPanelContext =
  createContext<DetailPanelContextValue | null>(null);

export function useDetailPanel(): DetailPanelContextValue {
  const ctx = useContext(DetailPanelContext);
  if (!ctx) {
    throw new Error(
      "DetailPanel.Header / .Body / .Actions must be used inside <DetailPanel>.",
    );
  }
  return ctx;
}

import { Info } from "lucide-react";
import { cn } from "@/lib/utils";

interface DetailPanelEmptyStateProps {
  title?: string;
  description?: string;
  className?: string;
}

export function DetailPanelEmptyState({
  title = "Nothing selected",
  description = "Select an item to view details.",
  className,
}: DetailPanelEmptyStateProps) {
  return (
    <div
      role="status"
      className={cn(
        "flex h-full flex-col items-center justify-center gap-2 p-6 text-center",
        className,
      )}
    >
      <Info aria-hidden="true" className="h-8 w-8 text-muted-foreground" />
      <p className="text-sm font-medium text-foreground">{title}</p>
      <p className="text-xs text-muted-foreground">{description}</p>
    </div>
  );
}

import { AlertCircle } from "lucide-react";
import { Button } from "@/components/ui/button";
import type { DetailPanelError as DetailPanelErrorShape } from "../types";

interface DetailPanelErrorProps {
  error: DetailPanelErrorShape;
}

export function DetailPanelError({ error }: DetailPanelErrorProps) {
  return (
    <div
      role="alert"
      className="flex h-full flex-col items-center justify-center gap-3 p-6 text-center"
    >
      <AlertCircle aria-hidden="true" className="h-8 w-8 text-destructive" />
      <p className="text-sm font-medium text-foreground">{error.message}</p>
      {error.retry ? (
        <Button variant="outline" size="sm" onClick={error.retry}>
          Try again
        </Button>
      ) : null}
    </div>
  );
}

"use client";

import type { DetailPanelHeaderProps } from "../types";
import { useDetailPanel } from "./detail-panel-context";
import { cn } from "@/lib/utils";

export function DetailPanelHeader({
  children,
  sticky = true,
  className,
}: DetailPanelHeaderProps) {
  // Verify Provider context exists; throws standard "must be inside <DetailPanel>" if not.
  useDetailPanel();
  return (
    <div
      className={cn(
        "z-10 flex items-center justify-between gap-3 border-b border-border bg-background px-4 py-3",
        sticky ? "sticky top-0" : undefined,
        className,
      )}
    >
      {children}
    </div>
  );
}

import { Skeleton } from "@/components/ui/skeleton";

export function DetailPanelSkeleton() {
  return (
    <div aria-hidden="true" className="flex h-full flex-col">
      <div className="border-b border-border p-4">
        <Skeleton className="h-6 w-3/5" />
        <Skeleton className="mt-2 h-4 w-2/5" />
      </div>
      <div className="flex-1 space-y-4 p-4">
        <Skeleton className="h-20 w-full" />
        <Skeleton className="h-20 w-full" />
        <Skeleton className="h-20 w-full" />
      </div>
      <div className="flex justify-end gap-2 border-t border-border p-4">
        <Skeleton className="h-9 w-20" />
        <Skeleton className="h-9 w-20" />
      </div>
    </div>
  );
}

import { EMPTY_SELECTION_KEY } from "../lib/selection-key";

interface SelectionAnnouncerProps {
  selectionKey: string;
}

export function SelectionAnnouncer({ selectionKey }: SelectionAnnouncerProps) {
  if (selectionKey === EMPTY_SELECTION_KEY) {
    return (
      <div
        role="status"
        aria-live="polite"
        aria-atomic="true"
        className="sr-only"
      />
    );
  }
  return (
    <div
      key={selectionKey}
      role="status"
      aria-live="polite"
      aria-atomic="true"
      className="sr-only"
    >
      Selection changed
    </div>
  );
}
